#!/bin/bash`n# в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—`n# в•‘        CubiVeil Unit Tests - Modular Structure            в•‘`n# в•‘        РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ РјРѕРґСѓР»СЊРЅРѕР№ Р°СЂС…РёС‚РµРєС‚СѓСЂС‹                в•‘`n# в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ`n`nset -euo pipefail`n`n# в”Ђв”Ђ РџРѕРґРєР»СЋС‡РµРЅРёРµ С‚РµСЃС‚РѕРІС‹С… СѓС‚РёР»РёС‚ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n# РСЃРїРѕР»СЊР·СѓРµРј СѓРЅРёРєР°Р»СЊРЅРѕРµ РёРјСЏ РїРµСЂРµРјРµРЅРЅРѕР№ С‡С‚РѕР±С‹ РёР·Р±РµР¶Р°С‚СЊ РїРµСЂРµР·Р°РїРёСЃРё`nMODULAR_SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"`nsource "${MODULAR_SCRIPT_DIR}/lib/test-utils.sh"`n`n# в”Ђв”Ђ РўРµСЃС‚: СЃС‚СЂСѓРєС‚СѓСЂР° РґРёСЂРµРєС‚РѕСЂРёР№ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_directory_structure() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ СЃС‚СЂСѓРєС‚СѓСЂС‹ РґРёСЂРµРєС‚РѕСЂРёР№..."`n`n  # РџСЂРѕРІРµСЂРєР° РѕСЃРЅРѕРІРЅС‹С… РґРёСЂРµРєС‚РѕСЂРёР№`n  local dirs=(`n    "lib"`n    "tests"`n  )`n`n  for dir in "${dirs[@]}"; do`n    if [[ -d "${MODULAR_SCRIPT_DIR}/${dir}" ]]; then`n      pass "Р”РёСЂРµРєС‚РѕСЂРёСЏ СЃСѓС‰РµСЃС‚РІСѓРµС‚: $dir"`n      ((TESTS_PASSED++)) || true`n    else`n      fail "Р”РёСЂРµРєС‚РѕСЂРёСЏ РѕС‚СЃСѓС‚СЃС‚РІСѓРµС‚: $dir"`n    fi`n  done`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: РЅР°Р»РёС‡РёРµ РѕСЃРЅРѕРІРЅС‹С… С„Р°Р№Р»РѕРІ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_main_files() {`n  info "Тестирование наличия основных файлов..."`n`n  local files=(`n    "install.sh"`n    "setup-telegram.sh"`n    "README.md"`n    "run-tests.sh"`n  )`n`n  for file in "${files[@]}"; do`n    if [[ -f "${MODULAR_SCRIPT_DIR}/${file}" ]]; then`n      pass "Файл существует: $file"`n      ((TESTS_PASSED++)) || true`n    else`n      warn "Файл отсутствует: $file"`n    fi`n  done`n}`n`n# ── Тест: модули lib ────────────────────────────────────────────────────────`ntest_lib_modules() {`n  info "Тестирование модулей в lib/..."`n`n  local lib_files=(`n    "lib/utils.sh"`n    "lib/common.sh"`n    "lib/validation.sh"`n    "lib/security.sh"`n    "lib/output.sh"`n    "lib/fallback.sh"`n    "lib/i18n.sh"`n    "lib/manifest.sh"`n  )`n`n  for file in "${lib_files[@]}"; do`n    if [[ -f "${MODULAR_SCRIPT_DIR}/${file}" ]]; then`n      pass "Модуль существует: $file"`n      ((TESTS_PASSED++)) || true`n    else`n      fail "Модуль отсутствует: $file"`n    fi`n  done`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: С‚РµСЃС‚РѕРІС‹Рµ С„Р°Р№Р»С‹ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_test_files() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ С‚РµСЃС‚РѕРІС‹С… С„Р°Р№Р»РѕРІ..."`n`n  local test_files=(`n    "tests/integration-test.sh"`n    "tests/unit-utils.sh"`n    "tests/unit-telegram.sh"`n    "tests/modular-structure.sh"`n  )`n`n  for file in "${test_files[@]}"; do`n    if [[ -f "${MODULAR_SCRIPT_DIR}/${file}" ]]; then`n      pass "РўРµСЃС‚РѕРІС‹Р№ С„Р°Р№Р» СЃСѓС‰РµСЃС‚РІСѓРµС‚: $file"`n      ((TESTS_PASSED++)) || true`n    else`n      warn "РўРµСЃС‚РѕРІС‹Р№ С„Р°Р№Р» РѕС‚СЃСѓС‚СЃС‚РІСѓРµС‚: $file"`n    fi`n  done`n}`n`n# ── Тест: синтаксис всех скриптов ───────────────────────────────────────────`ntest_all_syntax() {`n  info "Тестирование синтаксиса всех скриптов..."`n`n  local scripts=(`n    "install.sh"`n    "setup-telegram.sh"`n    "lib/utils.sh"`n    "lib/common.sh"`n    "tests/integration-test.sh"`n    "tests/unit-utils.sh"`n    "tests/unit-telegram.sh"`n    "tests/modular-structure.sh"`n    "run-tests.sh"`n  )`n`n  for script in "${scripts[@]}"; do`n    if [[ -f "${MODULAR_SCRIPT_DIR}/${script}" ]]; then`n      if bash -n "${MODULAR_SCRIPT_DIR}/${script}" 2>/dev/null; then`n        pass "Синтаксис OK: $script"`n        ((TESTS_PASSED++)) || true`n      else`n        fail "Синтаксическая ошибка: $script"`n      fi`n    fi`n  done`n}`n`n# ── Тест: исполнимость скриптов ─────────────────────────────────────────────`ntest_executable() {`n  info "Тестирование исполнимости скриптов..."`n`n  local exec_scripts=(`n    "install.sh"`n    "setup-telegram.sh"`n    "lib/utils.sh"`n    "tests/integration-test.sh"`n    "tests/unit-utils.sh"`n    "tests/unit-telegram.sh"`n    "tests/modular-structure.sh"`n    "run-tests.sh"`n  )`n`n  for script in "${exec_scripts[@]}"; do`n    local script_path="${MODULAR_SCRIPT_DIR}/${script}"`n    if [[ -f "$script_path" ]]; then`n      if [[ -x "$script_path" ]]; then`n        pass "Исполнимый: $script"`n        ((TESTS_PASSED++)) || true`n      else`n        warn "Не исполнимый: $script (chmod +x может понадобиться)"`n      fi`n    fi`n  done`n}`n`n# ── Тест: загрузка модулей ──────────────────────────────────────────────────`ntest_module_loading() {`n  info "Тестирование загрузки модулей..."`n`n  # Mock зависимостей`n  check_root() { :; }`n  check_ubuntu() { :; }`n  step() { echo "$1"; }`n  ok() { echo -e "${GREEN}[✓]${PLAIN} $1"; }`n  warn() { echo -e "${YELLOW}[!]${PLAIN} $1"; }`n  err() {`n    echo -e "${RED}[✗]${PLAIN} $1" >&2`n    exit 1`n  }`n`n  # Проверка загрузки lib/utils.sh`n  if bash -c "source ${MODULAR_SCRIPT_DIR}/lib/utils.sh 2>&1"; then`n    pass "Модуль загружается: lib/utils.sh"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "Модуль не загружается: lib/utils.sh"`n  fi`n`n  # Проверка загрузки lib/common.sh`n  if bash -c "source ${MODULAR_SCRIPT_DIR}/lib/common.sh 2>&1"; then`n    pass "Модуль загружается: lib/common.sh"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "Модуль не загружается: lib/common.sh"`n  fi`n`n  # Проверка загрузки lang/main.sh`n  if [[ -f "${MODULAR_SCRIPT_DIR}/lang/main.sh" ]]; then`n    if bash -c "source ${MODULAR_SCRIPT_DIR}/lang/main.sh 2>&1"; then`n      pass "Модуль загружается: lang/main.sh"`n      ((TESTS_PASSED++)) || true`n    else`n      warn "Модуль не загружается: lang/main.sh"`n    fi`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: С„СѓРЅРєС†РёРё РІ lib/utils.sh в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_utils_functions() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ С„СѓРЅРєС†РёР№ РІ lib/utils.sh..."`n`n  # Mock Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№`n  check_root() { :; }`n  check_ubuntu() { :; }`n  step() { echo "$1"; }`n  ok() { echo -e "${GREEN}[вњ“]${PLAIN} $1"; }`n  warn() { echo -e "${YELLOW}[!]${PLAIN} $1"; }`n  err() {`n    echo -e "${RED}[вњ—]${PLAIN} $1" >&2`n    exit 1`n  }`n`n  # Р—Р°РіСЂСѓР¶Р°РµРј РјРѕРґСѓР»СЊ`n  source "${MODULAR_SCRIPT_DIR}/lib/utils.sh"`n`n  local functions=(`n    "gen_random"`n    "gen_hex"`n    "gen_port"`n    "unique_port"`n    "arch"`n    "get_server_ip"`n    "open_port"`n  )`n`n  for func in "${functions[@]}"; do`n    if declare -f "$func" >/dev/null; then`n      pass "Р¤СѓРЅРєС†РёСЏ СЃСѓС‰РµСЃС‚РІСѓРµС‚: $func"`n      ((TESTS_PASSED++)) || true`n    else`n      fail "Р¤СѓРЅРєС†РёСЏ РѕС‚СЃСѓС‚СЃС‚РІСѓРµС‚: $func"`n    fi`n  done`n}`n`n# ── Тест: функции в install.sh ──────────────────────────────────────────────`ntest_install_functions() {`n  info "Тестирование функций в install.sh..."`n`n  # Mock зависимостей`n  check_root() { :; }`n  check_ubuntu() { :; }`n  step() { echo "$1"; }`n  step_title() { echo "$1"; }`n  ok() { echo -e "${GREEN}[✓]${PLAIN} $1"; }`n  warn() { echo -e "${YELLOW}[!]${PLAIN} $1"; }`n  err() {`n    echo -e "${RED}[✗]${PLAIN} $1" >&2`n    exit 1`n  }`n  info() { echo "[INFO] $1"; }`n`n  # Загружаем модули`n  source "${MODULAR_SCRIPT_DIR}/lib/utils.sh"`n  source "${MODULAR_SCRIPT_DIR}/lib/common.sh"`n`n  local functions=(`n    "prompt_inputs"`n    "_step_system"`n    "_step_firewall"`n    "_step_fail2ban"`n    "_step_singbox"`n    "_step_ssl"`n    "_step_decoy"`n    "_step_traffic_shaping"`n    "_step_telegram"`n    "_generate_keys_and_ports"`n  )`n`n  for func in "${functions[@]}"; do`n    if declare -f "$func" >/dev/null; then`n      pass "Функция существует: $func"`n      ((TESTS_PASSED++)) || true`n    else`n      fail "Функция отсутствует: $func"`n    fi`n  done`n}`n`n# ── Тест: отсутствие дублирования кода ──────────────────────────────────────`ntest_code_duplication() {`n  info "Тестирование отсутствия дублирования кода..."`n`n  # Проверка что install.sh не содержит код Telegram бота`n  if ! grep -q 'cubiveil-bot' "${MODULAR_SCRIPT_DIR}/install.sh" 2>/dev/null; then`n    pass "install.sh: не содержит код Telegram бота (правильно)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "install.sh: содержит код Telegram бота (дублирование!)"`n  fi`n`n  # Проверка что lib/utils.sh не содержит специфичный код установки`n  if ! grep -q 'step_' "${MODULAR_SCRIPT_DIR}/lib/utils.sh" 2>/dev/null; then`n    pass "lib/utils.sh: не содержит функции step_* (правильно)"`n    ((TESTS_PASSED++)) || true`n  else`n    warn "lib/utils.sh: содержит функции step_* (возможное дублирование)"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: СЂР°Р·РјРµСЂ С„Р°Р№Р»РѕРІ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_file_sizes() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ СЂР°Р·РјРµСЂРѕРІ С„Р°Р№Р»РѕРІ..."`n`n  # РџСЂРѕРІРµСЂРєР° С‡С‚Рѕ install.sh РЅРµ СЃР»РёС€РєРѕРј Р±РѕР»СЊС€РѕР№ (СЂРµС„Р°РєС‚РѕСЂРёРЅРі СѓРґР°Р»СЃСЏ)`n  local install_size`n  install_size=$(wc -l <"${MODULAR_SCRIPT_DIR}/install.sh" 2>/dev/null || echo "0")`n`n  if [[ $install_size -lt 200 ]]; then`n    pass "install.sh: РєРѕРјРїР°РєС‚РЅС‹Р№ (${install_size} СЃС‚СЂРѕРє)"`n    ((TESTS_PASSED++)) || true`n  elif [[ $install_size -lt 500 ]]; then`n    warn "install.sh: СѓРјРµСЂРµРЅРЅРѕРіРѕ СЂР°Р·РјРµСЂР° (${install_size} СЃС‚СЂРѕРє)"`n  else`n    fail "install.sh: СЃР»РёС€РєРѕРј Р±РѕР»СЊС€РѕР№ (${install_size} СЃС‚СЂРѕРє), РЅСѓР¶РµРЅ СЂРµС„Р°РєС‚РѕСЂРёРЅРі"`n  fi`n`n  # РџСЂРѕРІРµСЂРєР° С‡С‚Рѕ setup-telegram.sh РёРјРµРµС‚ СЂР°Р·СѓРјРЅС‹Р№ СЂР°Р·РјРµСЂ`n  local telegram_size`n  telegram_size=$(wc -l <"${MODULAR_SCRIPT_DIR}/setup-telegram.sh" 2>/dev/null || echo "0")`n`n  if [[ $telegram_size -gt 0 ]]; then`n    pass "setup-telegram.sh: СЃРѕРґРµСЂР¶РёС‚ РєРѕРґ (${telegram_size} СЃС‚СЂРѕРє)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "setup-telegram.sh: РїСѓСЃС‚ РёР»Рё РЅРµ РЅР°Р№РґРµРЅ"`n  fi`n`n  # РџСЂРѕРІРµСЂРєР° С‡С‚Рѕ lib/utils.sh РёРјРµРµС‚ СЂР°Р·СѓРјРЅС‹Р№ СЂР°Р·РјРµСЂ`n  local utils_size`n  utils_size=$(wc -l <"${MODULAR_SCRIPT_DIR}/lib/utils.sh" 2>/dev/null || echo "0")`n`n  if [[ $utils_size -gt 0 ]]; then`n    pass "lib/utils.sh: СЃРѕРґРµСЂР¶РёС‚ РєРѕРґ (${utils_size} СЃС‚СЂРѕРє)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "lib/utils.sh: РїСѓСЃС‚ РёР»Рё РЅРµ РЅР°Р№РґРµРЅ"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: РёРЅС‚РµРіСЂР°С†РёСЏ РјРѕРґСѓР»РµР№ РІ install.sh в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_install_sh_integration() {`n  info "Тестирование интеграции модулей в install.sh..."`n`n  # Проверка что install.sh загружает модули`n  if grep -q 'source.*lib/utils.sh' "${MODULAR_SCRIPT_DIR}/install.sh"; then`n    pass "install.sh: загружает lib/utils.sh"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "install.sh: не загружает lib/utils.sh"`n  fi`n`n  # Проверка загрузки модулей из lib/core/ (s-ui архитектура)`n  # install.sh использует lib/core/system.sh, lib/core/log.sh для s-ui`n  if grep -qE 'source.*lib/core/' "${MODULAR_SCRIPT_DIR}/install.sh"; then`n    pass "install.sh: загружает модули из lib/core/ (s-ui архитектура)"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "install.sh: не загружает модули из lib/core/"`n  fi`n`n  # Проверка что install.sh использует функции из модулей`n  if grep -q 'prompt_inputs\|_step_system\|_step_finish' "${MODULAR_SCRIPT_DIR}/install.sh"; then`n    pass "install.sh: использует функции из модулей"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "install.sh: не использует функции из модулей"`n  fi`n}`n`n# shellcheck disable=SC2218`n# в”Ђв”Ђ РћСЃРЅРѕРІРЅР°СЏ С„СѓРЅРєС†РёСЏ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nmain() {`n  echo ""`n  echo -e "${YELLOW}в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—${PLAIN}"`n  echo -e "${YELLOW}в•‘        CubiVeil Unit Tests - Modular Structure       в•‘${PLAIN}"`n  echo -e "${YELLOW}в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ${PLAIN}"`n  echo ""`n`n  info "РўРµСЃС‚РёСЂСѓРµРјС‹Р№ РїСЂРѕРµРєС‚: ${MODULAR_SCRIPT_DIR}"`n  echo ""`n`n  # в”Ђв”Ђ Р—Р°РїСѓСЃРє С‚РµСЃС‚РѕРІ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n  test_directory_structure`n  echo ""`n`n  test_main_files`n  echo ""`n`n  test_lib_modules`n  echo ""`n`n  test_test_files`n  echo ""`n`n  test_all_syntax`n  echo ""`n`n  test_executable`n  echo ""`n`n  test_module_loading`n  echo ""`n`n  test_utils_functions`n  echo ""`n`n  echo ""`n`n  test_code_duplication`n  echo ""`n`n  test_file_sizes`n  echo ""`n`n  test_install_sh_integration`n  echo ""`n`n  # в”Ђв”Ђ РС‚РѕРіРё в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n  echo ""`n  echo -e "${YELLOW}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${PLAIN}"`n  echo -e "${GREEN}РџСЂРѕР№РґРµРЅРѕ: $TESTS_PASSED${PLAIN}"`n  if [[ $TESTS_FAILED -gt 0 ]]; then`n    echo -e "${RED}РџСЂРѕРІР°Р»РµРЅРѕ:  $TESTS_FAILED${PLAIN}"`n  fi`n  echo -e "${YELLOW}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${PLAIN}"`n  echo ""`n`n  if [[ $TESTS_FAILED -gt 0 ]]; then`n    echo -e "${RED}вќЊ РўРµСЃС‚С‹ РїСЂРѕРІР°Р»РµРЅС‹${PLAIN}"`n    exit 1`n  else`n    echo -e "${GREEN}вњ… Р’СЃРµ С‚РµСЃС‚С‹ РїСЂРѕР№РґРµРЅС‹${PLAIN}"`n    exit 0`n  fi`n}`n`nmain "$@"`n
